<script>
  import { onMount } from "svelte";

  let background = $state(
    "data:image/jpeg;base64,",
  );
  let fields = $state([]);
  let editor = $state();
  let dragging = $state();
  let offsetX = 0;
  let offsetY = 0;
  let rect = $state();
  function uploadBackground(event) {
    const file = event.target.files[0];

    if (!file) return;

    const reader = new FileReader();

    reader.onload = () => {
      background = reader.result;
    };

    reader.readAsDataURL(file);
  }

  function addField() {
    fields = [
      ...fields,
      {
        id: crypto.randomUUID(),
        name: "New Field",
        x: 0.5,
        y: 0.5,
        fontSize: 24,
        color: "#000000",
      },
    ];
  }

  function startDrag(event, field) {
    dragging = field;
    console.log(event.clientX,field.x,rect.width);

    offsetX = event.clientX - field.x * rect.width;
    offsetY = event.clientY - field.y * rect.height;
  }

  function move(event) {
    if (!dragging) return;

    dragging.x = (event.clientX - offsetX) / rect.width;
    dragging.y = (event.clientY - offsetY) / rect.height;
    dragging.x = Math.max(0, Math.min(1, dragging.x));
    dragging.y = Math.max(0, Math.min(1, dragging.y));

    fields = [...fields];
  }

  function stopDrag() {
    dragging = null;
  }

  function removeField(id) {
    fields = fields.filter((f) => f.id !== id);
  }

  function saveTemplate() {
    localStorage.setItem(
      "template",
      JSON.stringify({
        background,
        fields,
      }),
    );

    alert("Template Saved");
  }

  function loadTemplate() {
    const saved = localStorage.getItem("template");

    if (!saved) return;

    const template = JSON.parse(saved);

    background = template.background;
    fields = template.fields;
  }

  onMount(() => {
    loadTemplate();
    rect = editor.getBoundingClientRect();
    window.addEventListener("mousemove", move);
    window.addEventListener("mouseup", stopDrag);

    return () => {
      window.removeEventListener("mousemove", move);
      window.removeEventListener("mouseup", stopDrag);
    };
  });
</script>

<div class="container-fluid p-3">
  <div class="card p-3 mb-3">
    <h3>Template Editor</h3>

    <input
      type="file"
      accept="image/*"
      onchange={uploadBackground}
      class="form-control mb-2"
    />

    <div class="d-flex gap-2">
      <button class="btn btn-success" onclick={addField}> Add Field </button>

      <button class="btn btn-primary" onclick={saveTemplate}>
        Save Template
      </button>

      <button class="btn btn-secondary" onclick={loadTemplate}>
        Load Template
      </button>
    </div>
  </div>

  <div class="row">
    <div class="col-md-3">
      {#each fields as field}
        <div class="card p-2 mb-2">
          <input class="form-control mb-2" bind:value={field.name} />

          <label>Font Size</label>

          <input
            type="number"
            class="form-control mb-2"
            bind:value={field.fontSize}
          />

          <label>Color</label>

          <input
            type="color"
            class="form-control form-control-color mb-2"
            bind:value={field.color}
          />

          <button class="btn btn-danger" onclick={() => removeField(field.id)}>
            Delete
          </button>
        </div>
      {/each}
    </div>

    <div class="col-md-9">
      <div class="editor">
        {#if background}
          <img src={background} alt="template" class="bg" bind:this={editor} />
        {/if}

        {#each fields as field}
          <div
            class="field"
            style:left="{(field.x * rect.width)}px"
            style:top="{(field.y * rect.height)}px"
            style:font-size="{field.fontSize}px"
            style:color={field.color}
            onmousedown={(e) => startDrag(e, field)}
          >
            {field.name}
          </div>
        {/each}
      </div>
    </div>
  </div>
</div>

<style>
  .editor {
    position: relative;
    border: 2px solid #666;
    background: #f0f0f0;
  }

  .bg {
    display: block;
    user-select: none;
    pointer-events: none;
  }

  .field {
    position: absolute;
    cursor: move;
    font-weight: bold;
    padding: 4px 8px;
    background: rgba(255, 255, 255, 0.8);
    border: 1px dashed #000;
    user-select: none;
  }
</style>
